// Tri-Bar Fidget Spinner — round hub + N arms ending in weighted lobes, all
// in the XY plane. Body is one labeled union; a contrasting center cap disc
// sits raised on the hub. Bores (center + each lobe) are subtracted last, so
// the model is intentionally non-solid (multiple components by design).
const { Manifold } = api;

const p = api.params({
  arms:      { type: 'int',    default: 3,  min: 2, max: 6, label: 'Arm count' },
  spanR:     { type: 'number', default: 22, min: 12, max: 40, step: 1, unit: 'mm', label: 'Hub-to-lobe distance' },
  lobeR:     { type: 'number', default: 9,  min: 5, max: 16, step: 0.5, unit: 'mm', label: 'Lobe radius' },
  thickness: { type: 'number', default: 7,  min: 3, max: 14, step: 0.5, unit: 'mm', label: 'Body thickness' },
  boreD:     { type: 'number', default: 10, min: 4, max: 18, step: 0.5, unit: 'mm', label: 'Bore diameter' },
});

const t = p.thickness;
const hubR = p.boreD / 2 + 5;          // hub wall around the central bore
const boreR = p.boreD / 2;
const lobeBoreR = Math.max(2, p.lobeR - 3.5);  // recess/hole in each lobe

// --- Hub: central round disc ---
const hub = Manifold.cylinder(t, hubR, hubR);

// --- Arms + lobes, one per spoke at evenly spaced angles ---
// Arm is a rounded-ish bar (a centered cube) that overlaps both the hub and its
// lobe; oversized length guarantees ≥0.5 unit volumetric overlap at both ends.
const armW = p.lobeR * 1.1;            // arm width tapers visually narrower than the lobe
const armLen = p.spanR + p.lobeR;      // spans from inside the hub out past the lobe center
const armBar = Manifold.cube([armLen, armW, t], true)
  .translate([armLen / 2 - 2, 0, t / 2]);  // pull inward 2u so it bites into the hub

const spokes = [];
for (let i = 0; i < p.arms; i++) {
  const deg = (360 / p.arms) * i;
  const lobe = Manifold.cylinder(t, p.lobeR, p.lobeR).translate([p.spanR, 0, 0]);
  spokes.push(armBar.add(lobe).rotate([0, 0, deg]));
}

// --- Body: hub + all spokes, unioned and labeled (vibrant blue) ---
let body = hub;
for (const s of spokes) body = body.add(s);

// --- Center cap: raised accent disc on top of the hub ---
const capR = hubR - 1;
const capH = 2;
const cap = Manifold.cylinder(capH, capR, capR).translate([0, 0, t - 0.5]); // overlap hub by 0.5

const assembled = api.labeledUnion([
  { name: 'body', shape: body, color: '#22a7ff' },
  { name: 'cap',  shape: cap,  color: '#ff3b6b' },
]);

// --- Bores: central through-hole + a recess/hole in every lobe ---
// Cut these last from the whole assembly. The center bore also pierces the cap.
const centerBore = Manifold.cylinder(t + capH + 2, boreR, boreR).translate([0, 0, -1]);

let holes = centerBore;
for (let i = 0; i < p.arms; i++) {
  const deg = (360 / p.arms) * i;
  const lobeBore = Manifold.cylinder(t + 2, lobeBoreR, lobeBoreR)
    .translate([p.spanR, 0, -1])
    .rotate([0, 0, deg]);
  holes = holes.add(lobeBore);
}

return assembled.subtract(holes);

